"use client";

import { useState } from "react";

const navLinks = [
  { label: "VEHICLES", href: "#" },
  { label: "BUILD YOUR OWN", href: "#" },
  { label: "SHOPPING TOOLS", href: "#" },
  { label: "OWNERS", href: "#" },
  { label: "EXPERIENCE", href: "#" },
];

export default function Header() {
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <header className="fixed top-0 left-0 right-0 z-50 bg-[#0c121c]/90 backdrop-blur-sm">
      <div className="flex items-center justify-between px-6 py-4 max-w-[1440px] mx-auto">
        {/* Logo */}
        <a href="/" className="flex-shrink-0">
          <svg
            viewBox="0 0 200 28"
            className="h-5 w-auto fill-white"
            aria-label="Land Rover"
          >
            <text
              x="0"
              y="22"
              fontFamily="LandRoverWeb-Bold, sans-serif"
              fontSize="20"
              letterSpacing="4"
              fill="white"
            >
              LAND ROVER
            </text>
          </svg>
        </a>

        {/* Desktop Nav */}
        <nav className="hidden lg:flex items-center gap-8">
          {navLinks.map((link) => (
            <a
              key={link.label}
              href={link.href}
              className="text-white text-xs tracking-[0.15em] font-medium hover:opacity-70 transition-opacity"
            >
              {link.label}
            </a>
          ))}
        </nav>

        {/* Right icons */}
        <div className="flex items-center gap-5">
          <button
            aria-label="Search"
            className="text-white hover:opacity-70 transition-opacity"
          >
            <svg
              width="20"
              height="20"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
            >
              <circle cx="11" cy="11" r="8" />
              <path d="m21 21-4.35-4.35" />
            </svg>
          </button>
          <button
            aria-label="Menu"
            className="lg:hidden text-white hover:opacity-70 transition-opacity"
            onClick={() => setMenuOpen(!menuOpen)}
          >
            <svg
              width="24"
              height="24"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
            >
              {menuOpen ? (
                <>
                  <path d="M18 6 6 18" />
                  <path d="m6 6 12 12" />
                </>
              ) : (
                <>
                  <path d="M4 6h16" />
                  <path d="M4 12h16" />
                  <path d="M4 18h16" />
                </>
              )}
            </svg>
          </button>
        </div>
      </div>

      {/* Mobile Nav */}
      {menuOpen && (
        <nav className="lg:hidden bg-[#0c121c] border-t border-white/10 px-6 py-4">
          {navLinks.map((link) => (
            <a
              key={link.label}
              href={link.href}
              className="block py-3 text-white text-sm tracking-[0.15em] font-medium border-b border-white/5"
            >
              {link.label}
            </a>
          ))}
        </nav>
      )}
    </header>
  );
}
